form:Form.form:Scripts:
		var xmlValidacion;

function onload()
{

	xmlValidacion = Ctrl('main').GetLastDocXML('XMLVAL');

  var cadena = "";

	for (var cur=xmlValidacion.FirstChild().FirstChild(); cur!=null; cur=cur.Next())
	{		
		cadena += cur.GetAttr("descr") + "\n";
		cadena += cur.GetAttr("monto1") + "\n";
		cadena += cur.GetAttr("monto2") + "\n\n";
	}

	Ctrl('info').SetCValue(cadena);

}
